B.Lm=new A.K(B.Y,"Conditionals describe cause and effect","Aviation procedures often describe what happens **if** a certain condition occurs. Emergency checklists, operational manuals, and exam questions rely heavily on conditional sentences.\n\nUnderstanding which conditional type to use depends on whether the situation is **real/possible** or **hypothetical/impossible**.",null,null,null)
B.Ni=new A.K(B.ek,"Conditional types at a glance",null,null,B.pp,null)
B.Lp=new A.K(B.A,"The Three Main Types",'**Type 1 \u2014 Real/Possible (present/future)**\nIf + present simple, will/can/must + base verb\n\u2192 "If the oil pressure drops, the pilot **will** declare an emergency."\n\n**Type 2 \u2014 Hypothetical (present/future)**\nIf + past simple, would/could + base verb\n\u2192 "If the engine **failed**, the crew **would** follow the ECAM."\n\n**Type 3 \u2014 Impossible (past)**\nIf + past perfect, would/could + have + past participle\n\u2192 "If the crew **had noticed** the leak, they **would have** diverted."',null,null,null)
B.Hd=new A.as("If the fuel quantity drops below minimum, the aircraft must return to base.","Yak\u0131t miktar\u0131 minimumun alt\u0131na d\xfc\u015ferse u\xe7ak \xfcsse d\xf6nmelidir.","If the fuel quantity drops")
B.Ib=new A.as("If the hydraulic system were to fail, the pilot would use backup controls.","Hidrolik sistem ar\u0131za yapsa pilot yedek kontrolleri kullan\u0131rd\u0131.","were to fail")
