B.Zo=new A.a2(-272,B.ak,642,'"Expect vectors" on a STAR means:',B.TD,1,B.aH,null,null,null)
B.Q4=s(["Climb to speed 220 knots","Maintain 220 KIAS or less","Set Mach 0.220","Not exceed 220 feet per minute climb"],t.s)
B.YV=new A.a2(-273,B.ak,643,'If a SID shows "S220" at a waypoint, the crew must:',B.Q4,1,B.aH,null,null,null)
